mapper.select:
select tk.tcId as tkid, cr.crId as crid, cr.crCode as crcode, cr.crName as crname, cr.crCredit as crcredit, cr.crPeriod as crperiod, cr.crType as crtype, cr.crExamType as crexamtype, t.tId as tid, t.tName as tname, yt.yId as ytid, yt.yAll as ytname, c.cId as cid, c.cName as cname from teaching tk inner join studentinfo s on s.sClassId = tk.tcClassId left join courseinfo cr on tk.tcCourseId = cr.crId left join teacherinfo t on tk.tcTeacherId = t.tId left join yearterm yt on tk.tcTermId = yt.yId left join classinfo c on tk.tcClassId = c.cId where s.sAccountId = #{uid}
and ( cr.crName like concat('%', #{query.qkey}, '%') or cr.crCode like concat('%', #{query.qkey}, '%') )
and tk.tcTermId = #{query.ytid}
order by yt.yId desc, tk.tcId desc
